// Stub hardhat type augmentation — generated by hardhat compile in CI.
// Augments `hardhat/types/runtime` so that `ethers.getContractFactory(name)`
// returns properly-typed factory instances for each contract.

import type { ethers } from "ethers";
import type {
  DeployContractOptions,
  FactoryOptions,
  HardhatEthersHelpers as HardhatEthersHelpersBase,
} from "@nomicfoundation/hardhat-ethers/types";

import type * as Contracts from ".";

declare module "hardhat/types/runtime" {
  interface HardhatEthersHelpers extends HardhatEthersHelpersBase {
    // getContractFactory overloads
    getContractFactory(
      name: "AetheronBridge",
      signerOrOptions?: ethers.Signer | FactoryOptions,
    ): Promise<Contracts.AetheronBridge__factory>;

    getContractFactory(
      name: "SentinelInterceptor",
      signerOrOptions?: ethers.Signer | FactoryOptions,
    ): Promise<Contracts.SentinelInterceptor__factory>;

    getContractFactory(
      name: "MockToken",
      signerOrOptions?: ethers.Signer | FactoryOptions,
    ): Promise<Contracts.MockToken__factory>;

    getContractFactory(
      name: "MockBridge",
      signerOrOptions?: ethers.Signer | FactoryOptions,
    ): Promise<Contracts.MockBridge__factory>;

    getContractFactory(
      name: "AnomalyDetectionOracle",
      signerOrOptions?: ethers.Signer | FactoryOptions,
    ): Promise<Contracts.AnomalyDetectionOracle__factory>;

    getContractFactory(
      name: "ExploitForecastOracle",
      signerOrOptions?: ethers.Signer | FactoryOptions,
    ): Promise<Contracts.ExploitForecastOracle__factory>;

    getContractFactory(
      name: "RateLimiter",
      signerOrOptions?: ethers.Signer | FactoryOptions,
    ): Promise<Contracts.RateLimiter__factory>;

    getContractFactory(
      name: "CircuitBreaker",
      signerOrOptions?: ethers.Signer | FactoryOptions,
    ): Promise<Contracts.CircuitBreaker__factory>;

    // getContractAt overloads
    getContractAt(
      name: "AetheronBridge",
      address: string | ethers.Addressable,
      signer?: ethers.Signer,
    ): Promise<Contracts.AetheronBridge>;

    getContractAt(
      name: "SentinelInterceptor",
      address: string | ethers.Addressable,
      signer?: ethers.Signer,
    ): Promise<Contracts.SentinelInterceptor>;

    getContractAt(
      name: "MockToken",
      address: string | ethers.Addressable,
      signer?: ethers.Signer,
    ): Promise<Contracts.MockToken>;

    getContractAt(
      name: "MockBridge",
      address: string | ethers.Addressable,
      signer?: ethers.Signer,
    ): Promise<Contracts.MockBridge>;

    // deployContract overloads
    deployContract(
      name: "AetheronBridge",
      signerOrOptions?: ethers.Signer | DeployContractOptions,
    ): Promise<Contracts.AetheronBridge>;
    deployContract(
      name: "AetheronBridge",
      args: any[],
      signerOrOptions?: ethers.Signer | DeployContractOptions,
    ): Promise<Contracts.AetheronBridge>;

    deployContract(
      name: "SentinelInterceptor",
      signerOrOptions?: ethers.Signer | DeployContractOptions,
    ): Promise<Contracts.SentinelInterceptor>;
    deployContract(
      name: "SentinelInterceptor",
      args: any[],
      signerOrOptions?: ethers.Signer | DeployContractOptions,
    ): Promise<Contracts.SentinelInterceptor>;

    deployContract(
      name: "MockToken",
      signerOrOptions?: ethers.Signer | DeployContractOptions,
    ): Promise<Contracts.MockToken>;
    deployContract(
      name: "MockToken",
      args: any[],
      signerOrOptions?: ethers.Signer | DeployContractOptions,
    ): Promise<Contracts.MockToken>;

    deployContract(
      name: "MockBridge",
      signerOrOptions?: ethers.Signer | DeployContractOptions,
    ): Promise<Contracts.MockBridge>;
    deployContract(
      name: "MockBridge",
      args: any[],
      signerOrOptions?: ethers.Signer | DeployContractOptions,
    ): Promise<Contracts.MockBridge>;

    // fallback (default types kept)
    getContractFactory(
      name: string,
      signerOrOptions?: ethers.Signer | FactoryOptions,
    ): Promise<ethers.ContractFactory>;
    getContractFactory(
      abi: any[],
      bytecode: ethers.BytesLike,
      signer?: ethers.Signer,
    ): Promise<ethers.ContractFactory>;
    getContractAt(
      nameOrAbi: string | any[],
      address: string | ethers.Addressable,
      signer?: ethers.Signer,
    ): Promise<ethers.Contract>;
    deployContract(
      name: string,
      signerOrOptions?: ethers.Signer | DeployContractOptions,
    ): Promise<ethers.Contract>;
    deployContract(
      name: string,
      args: any[],
      signerOrOptions?: ethers.Signer | DeployContractOptions,
    ): Promise<ethers.Contract>;
  }
}
